import os
import torch
import pandas as pd
from tqdm import tqdm
from transformers import Wav2Vec2ForCTC, Wav2Vec2Processor
from datasets import load_dataset
from jiwer import wer, cer

# --- Configuration ---
BASE_DIR = "Deep-Learning-Final-Project/models/train/results_old"
# Update this to the path of the metadata CSV generated by the LibriMix script
LIBRIMIX_TEST_CSV = "Libri2Mix/wav16k/test/metadata/libri2mix_test_clean.csv"
OUTPUT_FILE = "evaluation_results.txt"
DEVICE = "cuda" if torch.cuda.is_available() else "cpu"

def evaluate_models():
    results = []
    
    # 1. Load the LibriMix test data
    # LibriMix metadata typically has 'mixture_path' and 'transcript' columns
    df_test = pd.read_csv(LIBRIMIX_TEST_CSV)
    
    # 2. Traverse directories for Wav2Vec2 checkpoints
    print(f"Searching for checkpoints in {BASE_DIR}...")
    checkpoint_paths = []
    for root, dirs, files in os.walk(BASE_DIR):
        # Look for folders containing a pytorch_model.bin or model.safetensors
        if "checkpoint-" in root or any(f in files for f in ["config.json", "pytorch_model.bin"]):
            # Filter specifically for your fine-tuned wav2vec2 models
            if "wav2vec2" in root.lower():
                checkpoint_paths.append(root)

    if not checkpoint_paths:
        print("No wav2vec2 checkpoints found. Check your directory paths.")
        return

    # 3. Process each checkpoint
    for ckpt in checkpoint_paths:
        print(f"\nEvaluating: {ckpt}")
        try:
            # Load model and processor
            processor = Wav2Vec2Processor.from_pretrained(ckpt)
            model = Wav2Vec2ForCTC.from_pretrained(ckpt).to(DEVICE)
            
            predictions = []
            references = []

            # 4. Inference Loop
            for _, row in tqdm(df_test.iterrows(), total=len(df_test), desc="Inference"):
                audio_path = row['mixture_path'] 
                target_text = row['transcript'].upper() # ASR usually expects uppercase
                
                # Load audio
                import librosa
                speech, _ = librosa.load(audio_path, sr=16000)
                
                inputs = processor(speech, sampling_rate=16000, return_tensors="pt", padding=True)
                with torch.no_grad():
                    logits = model(inputs.input_values.to(DEVICE)).logits
                
                pred_ids = torch.argmax(logits, dim=-1)
                transcription = processor.batch_decode(pred_ids)[0]
                
                predictions.append(transcription)
                references.append(target_text)

            # Calculate Metrics
            error_wer = wer(references, predictions)
            error_cer = cer(references, predictions)
            
            res_str = f"Model: {ckpt}\nWER: {error_wer:.4f} | CER: {error_cer:.4f}\n" + ("-"*30)
            print(res_str)
            results.append(res_str)
            
        except Exception as e:
            print(f"Error evaluating {ckpt}: {e}")

    # 5. Output to Text File
    with open(OUTPUT_FILE, "w") as f:
        f.write("\n".join(results))
    print(f"\nAll results saved to {OUTPUT_FILE}")

if __name__ == "__main__":
    evaluate_models()